  it("should propagate actual errors from source when terminating with last=false", (done) => {
    const actualError = new Error("source error");
    let callCount = 0;

    function source(end: any, cb: Function) {
      if (end) {
        cb(actualError);
        return;
      }
      callCount++;
      cb(null, callCount === 1 ? "item1" : "item2");
    }

    const through = take(function(data: any) {
      return data === "item1";
    }, { last: false });

    const reader = through(source);

    reader(null, function(end: any, data: any) {
      reader(null, function(end2: any, data2: any) {
        if (end2 === actualError) {
          done();
        } else if (end2 === true) {
          done(new Error("Mutated: got true instead of actual error"));
        } else {
          done(new Error("Unexpected: end2=" + end2));
        }
      });
    });
  });
});
